#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <stdbool.h>
#include <gmp.h> // GNU MP for big integers

typedef struct {int prev; char *part; } Prev;

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        char S[130]; char Nstr[130];
        scanf("%s %s", S, Nstr);
        int L = strlen(S);
        mpz_t N; mpz_init_set_str(N, Nstr, 10);
        // DP: vector of hash tables (value -> Prev)
        typedef struct Node{ mpz_t sum; int prev; int pos; struct Node* next; } Node;
        // For simplicity and because constraints are tiny we use a linked list per position.
        Node* dp[131] = {0};
        // base state sum=0 at position 0
        Node* base = (Node*)malloc(sizeof(Node));
        mpz_init_set_ui(base->sum, 0);
        base->prev = -1; base->pos = -1; base->next = NULL;
        dp[0] = base;
        for(int i=1;i<=L;i++){
            for(int j=0;j<i;j++){
                // substring S[j..i-1]
                char buf[130]; memcpy(buf, S+j, i-j); buf[i-j]='\0';
                mpz_t val; mpz_init_set_str(val, buf, 10);
                for(Node* cur=dp[j]; cur; cur=cur->next){
                    mpz_t cand; mpz_init(cand);
                    mpz_add(cand, cur->sum, val);
                    if(mpz_cmp(cand, N) > 0){ mpz_clear(cand); continue; }
                    // store new state
                    Node* nd = (Node*)malloc(sizeof(Node));
                    mpz_init_set(nd->sum, cand);
                    nd->prev = j; nd->pos = i; nd->next = dp[i];
                    dp[i] = nd;
                    mpz_clear(cand);
                }
                mpz_clear(val);
            }
        }
        // find state with sum == N at position L
        Node* target = NULL;
        for(Node* cur=dp[L]; cur; cur=cur->next){
            if(mpz_cmp(cur->sum, N)==0){ target=cur; break; }
        }
        // reconstruct
        char *parts[130]; int cnt=0;
        int pos = L; Node* cur = target;
        while(cur && cur->prev!=-1){
            int start = cur->prev;
            int len = pos - start;
            parts[cnt] = (char*)malloc(len+1);
            memcpy(parts[cnt], S+start, len);
            parts[cnt][len]='\0';
            cnt++;
            pos = start;
            // move to previous node
            for(Node* p=dp[start]; p; p=p->next){ if(mpz_cmp(p->sum, cur->sum) == 0 && p->pos==start){ cur=p; break; } }
        }
        // output in reverse order
        for(int i=cnt-1;i>=0;i--){
            printf("%s", parts[i]);
            if(i) printf("+");
        }
        printf("\n");
        // cleanup omitted for brevity
        mpz_clear(N);
    }
    return 0;
}

