#include <bits/stdc++.h>
#include <boost/multiprecision/cpp_int.hpp>
using namespace std;
using boost::multiprecision::cpp_int;

struct Prev{int prev; cpp_int val;};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        string S, Nstr; cin>>S>>Nstr;
        int L=S.size();
        cpp_int N=0; for(char c:Nstr) N=N*10+(c-'0');
        vector<unordered_map<cpp_int, Prev>> dp(L+1);
        dp[0][0]={-1,0};
        for(int i=1;i<=L;i++){
            for(int j=0;j<i;j++){
                cpp_int val=0;
                for(int k=j;k<i;k++) val=val*10+(S[k]-'0');
                for(const auto &pr: dp[j]){
                    cpp_int ns = pr.first + val;
                    if(ns > N) continue;
                    if(dp[i].find(ns)==dp[i].end()) dp[i][ns] = {j,val};
                }
            }
        }
        // reconstruct
        vector<string> parts;
        int pos=L; cpp_int cur=N;
        while(pos>0){
            auto it = dp[pos].find(cur);
            int j = it->second.prev;
            string part = S.substr(j, pos-j);
            parts.push_back(part);
            cur -= it->second.val;
            pos = j;
        }
        for(int i=parts.size()-1;i>=0;i--){
            cout<<parts[i];
            if(i) cout<<'+';
        }
        cout<<"\n";
    }
    return 0;
}

