import java.io.*;
import java.util.*;
import java.math.BigInteger;

public class Main {
    static class Prev {
        int prev;
        BigInteger val;
        Prev(int p, BigInteger v){prev=p;val=v;}
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            String line = br.readLine();
            String[] parts = line.trim().split(" ");
            String S = parts[0];
            BigInteger N = new BigInteger(parts[1]);
            int L = S.length();
            @SuppressWarnings("unchecked")
            HashMap<BigInteger, Prev>[] dp = new HashMap[L+1];
            for (int i=0;i<=L;i++) dp[i]=new HashMap<>();
            dp[0].put(BigInteger.ZERO, new Prev(-1, BigInteger.ZERO));
            for (int i=1;i<=L;i++) {
                for (int j=0;j<i;j++) {
                    BigInteger val = new BigInteger(S.substring(j,i));
                    for (Map.Entry<BigInteger, Prev> e: dp[j].entrySet()) {
                        BigInteger ns = e.getKey().add(val);
                        if (ns.compareTo(N)>0) continue;
                        dp[i].putIfAbsent(ns, new Prev(j,val));
                    }
                }
            }
            // reconstruction
            List<String> out = new ArrayList<>();
            int pos = L;
            BigInteger cur = N;
            while (pos>0) {
                Prev pr = dp[pos].get(cur);
                int j = pr.prev;
                out.add(S.substring(j,pos));
                cur = cur.subtract(pr.val);
                pos = j;
            }
            for (int i=out.size()-1;i>=0;i--) {
                System.out.print(out.get(i));
                if (i>0) System.out.print('+');
            }
            System.out.println();
        }
    }
}

