const fs = require('fs');
const input = fs.readFileSync(0, 'utf8').trim().split(/\n/);
let idx = 0;
const T = parseInt(input[idx++]);
let results = [];
for (let tc = 0; tc < T; tc++) {
  const [S, Nstr] = input[idx++].trim().split(' ');
  const N = BigInt(Nstr);
  const L = S.length;
  const dp = Array.from({ length: L + 1 }, () => new Map());
  dp[0].set(0n, { prev: -1, val: 0n });
  for (let end = 1; end <= L; end++) {
    for (let start = 0; start < end; start++) {
      const val = BigInt(S.slice(start, end));
      for (const [sum, info] of dp[start]) {
        const ns = sum + val;
        if (ns > N) continue;
        if (!dp[end].has(ns)) dp[end].set(ns, { prev: start, val });
      }
    }
  }
  // reconstruction
  let parts = [];
  let pos = L;
  let cur = N;
  while (pos > 0) {
    const info = dp[pos].get(cur);
    const start = info.prev;
    parts.push(S.slice(start, pos));
    cur -= info.val;
    pos = start;
  }
  results.push(parts.reverse().join('+'));
}
